def solve(level, data):
    if level < 1 or level > 4:
        raise ValueError("Level must be between 1 and 4.")

    if not isinstance(data, list):
        raise TypeError("Data must be a list.")

    if level == 1:
        return sum(data)  # Example behavior for Level 1
    elif level == 2:
        return max(data)  # Example behavior for Level 2
    elif level == 3:
        return min(data)  # Example behavior for Level 3
    elif level == 4:
        return len(data)  # Example behavior for Level 4
